from PIL import Image

# Slide 2 - full horizontal layout at key vertical positions
img = Image.open('/Users/admin/slide-2.jpg')
w, h = img.size

print('=== SLIDE 2 - HORIZONTAL CONTENT AT KEY VERTICAL POSITIONS ===')
for y_val in [249, 255, 263, 270, 280, 290, 300, 310, 317, 324, 400, 482, 490, 500, 549, 600]:
    row = [img.getpixel((x, y_val)) for x in range(50, 750, 3)]
    non_bg = [(i*3+50, p) for i, p in enumerate(row) 
              if abs(p[0]-248) > 10 or abs(p[1]-249) > 10 or abs(p[2]-253) > 10]
    if non_bg:
        # Group by color similarity
        groups = []
        current_group = {'start': non_bg[0][0], 'end': non_bg[0][0], 'color': non_bg[0][1], 'pixels': []}
        for x, p in non_bg:
            if x - current_group['end'] > 15:
                groups.append(current_group)
                current_group = {'start': x, 'end': x, 'color': p, 'pixels': []}
            current_group['end'] = x
            current_group['pixels'].append((x, p))
        groups.append(current_group)

        desc = []
        for g in groups:
            span = g['end'] - g['start']
            c = g['color']
            # Categorize
            if c[1] > 140 and c[0] < 120 and c[2] > 140:
                cat = 'TEAL'
            elif c[0] < 50 and c[1] < 50 and c[2] < 80:
                cat = 'BLACK'
            elif c[0] < 80 and c[1] < 80 and c[2] < 120:
                cat = 'DARK'
            elif c[0] > 200 and c[1] > 200 and c[2] > 200:
                cat = 'LIGHT'
            else:
                cat = f'RGB({c[0]},{c[1]},{c[2]})'
            desc.append(f'{cat}[{g[\"start\"]}-{g[\"end\"]}]({span}px)')

        print(f'  y={y_val}: {\", \".join(desc)}')
    else:
        print(f'  y={y_val}: (empty)')
